import{_ as a,c as o,a as t,o as d}from"./app-CEcM0piI.js";const p={};function c(r,e){return d(),o("div",null,e[0]||(e[0]=[t('<p>可以将一组需要布局管理的组件放在一个容器组件中，这样，当容器大小变化时，里面的组件也会自动变化。</p><h1 id="水平布局" tabindex="-1"><a class="header-anchor" href="#水平布局"><span>水平布局</span></a></h1><p>![[Clip_2024-03-11_21-38-43.png]] layoutStretch：0,0,0，表示3个组件平均分配宽度 layoutStretch：0,0,1，表示前两个组件达到合适宽度后不再增加宽度，其余的空间都分配给第三个组件 layoutStretch：1,1,2，表示前两个组件达到合适宽度后将尽量满足1:1:2的比例。</p><p>QMainWindow是一个为用户提供主窗口程序的类，包含一个菜单栏（menubar）多个工具栏（toolbars）、多个锚接部件（dockwidgets）、一个状态栏（statusbar）及一个中心部件（centralwidget），是许多应用程序的基础，如文本编辑器，图片编辑器等。</p><h3 id="菜单栏" tabindex="-1"><a class="header-anchor" href="#菜单栏"><span>菜单栏</span></a></h3><p>一个页面中菜单栏只有一个</p><ol><li><p>创建 菜单栏需要手动创建 使用<code>menuBar</code>,返回指向菜单栏的指针</p></li><li><p>显示 使用<code>setMenuBar</code>显示菜单栏 如果里面没有菜单则不显示</p></li><li><p>添加元素 因为菜单只能出现在菜单栏所以无法单独创建 需要调用menuBar类的<code>addMenu</code>创建并添加进去返回指向菜单的QMenu指针</p></li><li><p>创建菜单项 一个菜单有多个选项, 通过调用QMenu菜单类中的<code>addAction</code>在当前菜单中添加菜单项</p></li></ol><p><strong>分割线</strong> 在一个菜单中有多个菜单项,其中有的菜单项属于同一组,可以使用分割线与其他属的菜单项分隔开 <code>addSeparator</code></p><h3 id="工具栏" tabindex="-1"><a class="header-anchor" href="#工具栏"><span>工具栏</span></a></h3><p>可以有多个</p><ol><li><p>创建工具栏 通过<code>QToolBar</code>构造函数创建工具栏</p></li><li><p>显示 通过调用<code>addToolBar</code>添加到当前窗口中,默认是停靠在顶部菜单栏下面的,可以调用它的重载函数添加Qt枚举值参数设置停靠位置 如:<code>addToolBar(Qt::LeftToolBarArea,toolbar)</code>使工具栏停靠在左侧</p></li></ol><p><strong>限制停靠范围</strong> 使用其成员函数<code>setAllowArea</code>使用枚举值参数设置限制的停靠范围,如果有多个区域需要设置各枚举值使用 | 隔开 如果吧工具栏拖到了不允许的停靠范围, 工具栏就会浮动地停靠在那里</p><p><strong>设置浮动</strong> 可以使用<code>setFloatable</code>设置是否浮动</p><p><strong>设置移动</strong> 使用<code>setMovable</code>设置是否可移动</p><p>工具栏中也可以添加分割线</p><p><strong>添加控件</strong> 工具栏中也可以添加控件 ,使用<code>addWidget</code>函数</p><h3 id="状态栏" tabindex="-1"><a class="header-anchor" href="#状态栏"><span>状态栏</span></a></h3><p>一个窗口最多有一个</p><ol><li><p>显示 状态栏本身就存在只不过是被隐藏了 可以使用指针接收<code>statusBar</code>返回的状态栏指针来操作状态栏 使用<code>setStatusBar</code>将状态栏设置到窗口中</p></li><li><p>添加元素 <code>addWidget</code>往状态栏左边添加元素 <code>addPermanentWidget</code>往状态栏右边添加元素</p></li></ol><h3 id="铆接部件-浮动窗口" tabindex="-1"><a class="header-anchor" href="#铆接部件-浮动窗口"><span>铆接部件 ( 浮动窗口 )</span></a></h3><ol><li><p>创建 使用构造函数<code>QDockWidget</code>创建</p></li><li><p>添加 使用<code>addDockWidget</code>将铆接固件添加到当前窗口中 可以设置停靠区域, 浮动窗口是围绕着核心的,如果没有指定核心设置停靠区域可能会出现与预期不符的情况</p></li><li><p>设置核心 使用<code>setCentralWidget</code>设置核心 核心只能有一个,如:word中核心可能就是中间编辑的文本框</p></li></ol>',21)]))}const i=a(p,[["render",c]]),l=JSON.parse('{"path":"/cpp/qt/10/","title":"10 布局管理","lang":"zh-CN","frontmatter":{"title":"10 布局管理","createTime":"2025/06/22 10:39:50","permalink":"/cpp/qt/10/"},"readingTime":{"minutes":2.89,"words":867},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/Qt/10 布局管理.md","headers":[]}');export{i as comp,l as data};
